import React, { useEffect, useState, useCallback } from 'react';
import { Book, Category } from '../types';
import api from '../utils/api';
import { useAuth } from '../hooks/useAuth';

const E: Partial<Book> = { title:'', author:'', isbn:'', publisher:'', published_year: new Date().getFullYear(), description:'', total_copies:1, location:'', language:'English', pages:0 };
const inp: React.CSSProperties = { width:'100%', padding:'8px 12px', border:'2px solid #e8e0d0', borderRadius:9, fontSize:13, fontFamily:'inherit', outline:'none', color:'#1a1a2e' };
const lbl: React.CSSProperties = { display:'block', fontSize:12, fontWeight:600, color:'#6b7280', marginBottom:6 };

export default function Books() {
  const { user } = useAuth();
  const isStaff = user?.userType === 'user';
  const [books, setBooks] = useState<Book[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState('');
  const [catFilter, setCatFilter] = useState('');
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState<'add'|'edit'|null>(null);
  const [form, setForm] = useState<Partial<Book>>(E);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [borrowMsg, setBorrowMsg] = useState('');
  const [borrowingId, setBorrowingId] = useState<number|null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const { data } = await api.get('/books', { params: { search, category: catFilter, page, limit: 9 } });
      setBooks(data.data || []); setTotal(data.total || 0);
    } finally { setLoading(false); }
  }, [search, catFilter, page]);

  useEffect(() => { load(); }, [load]);
  useEffect(() => { api.get('/borrows/categories').then(r => setCategories(r.data.data)); }, []);

  const borrowBook = async (bookId: number) => {
    setBorrowingId(bookId); setBorrowMsg('');
    try {
      const { data } = await api.post('/borrows/request', { book_id: bookId });
      setBorrowMsg('✓ ' + data.message);
      load();
    } catch (e: any) {
      setBorrowMsg('✕ ' + (e.response?.data?.message || 'Error'));
    } finally {
      setBorrowingId(null);
      setTimeout(() => setBorrowMsg(''), 4000);
    }
  };

  const save = async () => {
    if (!form.title || !form.author) { setError('Title and Author required!'); return; }
    setSaving(true); setError('');
    try {
      if (modal === 'add') await api.post('/books', form);
      else await api.put(`/books/${form.id}`, form);
      setModal(null); load();
    } catch (e: any) { setError(e.response?.data?.message || 'Error'); }
    finally { setSaving(false); }
  };

  const del = async (id: number) => {
    if (!window.confirm('Delete this book?')) return;
    await api.delete(`/books/${id}`); load();
  };

  return (
    <div className="page-enter" style={{ padding: 32 }}>
      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:24 }}>
        <div>
          <h1 style={{ fontFamily:"'Playfair Display',serif", fontSize:28, fontWeight:700 }}>Books</h1>
          <p style={{ color:'#9ca3af', fontSize:13, marginTop:4 }}>{total} books in collection</p>
        </div>
        {isStaff && (
          <button onClick={() => { setForm({...E}); setError(''); setModal('add'); }}
            style={{ padding:'9px 20px', background:'#1a1a2e', color:'#fff', border:'none', borderRadius:10, fontSize:13, fontWeight:600, cursor:'pointer', fontFamily:'inherit' }}>
            + Add Book
          </button>
        )}
      </div>

      {borrowMsg && (
        <div style={{ background: borrowMsg.startsWith('✓') ? '#d1fae5' : '#fee2e2', color: borrowMsg.startsWith('✓') ? '#059669' : '#dc2626', padding:'12px 16px', borderRadius:10, fontSize:13, fontWeight:600, marginBottom:16 }}>
          {borrowMsg}
        </div>
      )}

      <div style={{ display:'flex', gap:12, marginBottom:20, flexWrap:'wrap' }}>
        <input style={{ ...inp, flex:1, minWidth:200, paddingLeft:14 }} value={search} onChange={e => { setSearch(e.target.value); setPage(1); }} placeholder="🔍  Search title, author, ISBN..." />
        <select style={{ ...inp, width:180 }} value={catFilter} onChange={e => { setCatFilter(e.target.value); setPage(1); }}>
          <option value="">All Categories</option>
          {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
        </select>
      </div>

      {loading ? (
        <div style={{ textAlign:'center', padding:80 }}>Loading...</div>
      ) : (
        <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:16 }}>
          {books.map(b => {
            const cat = categories.find(c => c.id === b.category_id);
            const color = b.category_color || cat?.color || '#6366f1';
            const pct = Math.round((b.available_copies / b.total_copies) * 100) || 0;
            return (
              <div key={b.id} style={{ background:'#fff', border:'1px solid #e8e0d0', borderRadius:16, padding:18 }}>
                <div style={{ display:'flex', justifyContent:'space-between', marginBottom:10 }}>
                  <span style={{ fontSize:11, fontWeight:600, padding:'3px 10px', borderRadius:99, background:color+'20', color }}>{b.category_name || cat?.name || 'General'}</span>
                  {isStaff && (
                    <div style={{ display:'flex', gap:4 }}>
                      <button onClick={() => { setForm(b); setError(''); setModal('edit'); }} style={{ padding:'4px 10px', background:'#f5f0e8', border:'none', borderRadius:7, fontSize:12, cursor:'pointer' }}>✏️</button>
                      <button onClick={() => del(b.id)} style={{ padding:'4px 10px', background:'#fee2e2', border:'none', borderRadius:7, fontSize:12, cursor:'pointer' }}>🗑️</button>
                    </div>
                  )}
                </div>
                <h3 style={{ fontFamily:"'Playfair Display',serif", fontSize:15, fontWeight:700, marginBottom:4, lineHeight:1.3 }}>{b.title}</h3>
                <p style={{ fontSize:12, color:'#9ca3af', marginBottom:8 }}>{b.author} · {b.published_year}</p>
                <p style={{ fontSize:12, color:'#6b7280', lineHeight:1.5, marginBottom:14, display:'-webkit-box', WebkitLineClamp:2, WebkitBoxOrient:'vertical', overflow:'hidden' }}>{b.description}</p>
                <div style={{ borderTop:'1px solid #e8e0d0', paddingTop:12 }}>
                  <div style={{ display:'flex', justifyContent:'space-between', marginBottom:6 }}>
                    <span style={{ fontSize:12, color:'#6b7280' }}>Availability</span>
                    <span style={{ fontSize:12, fontWeight:600, color: b.available_copies > 0 ? '#059669' : '#dc2626' }}>{b.available_copies}/{b.total_copies}</span>
                  </div>
                  <div style={{ height:5, background:'#e8e0d0', borderRadius:99 }}>
                    <div style={{ height:'100%', borderRadius:99, width:`${pct}%`, background: b.available_copies > 0 ? '#10b981' : '#ef4444', transition:'width .5s' }} />
                  </div>
                  <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginTop:10 }}>
                    <span style={{ fontSize:11, color:'#9ca3af', fontFamily:'monospace' }}>{b.location || '—'}</span>
                    {/* Student/Staff এর জন্য Borrow button */}
                    {!isStaff && (
                      <button
                        onClick={() => borrowBook(b.id)}
                        disabled={b.available_copies < 1 || borrowingId === b.id}
                        style={{ padding:'5px 14px', background: b.available_copies > 0 ? '#1a1a2e' : '#e8e0d0', color: b.available_copies > 0 ? '#fff' : '#9ca3af', border:'none', borderRadius:8, fontSize:12, fontWeight:600, cursor: b.available_copies > 0 ? 'pointer' : 'not-allowed', fontFamily:'inherit' }}>
                        {borrowingId === b.id ? '...' : b.available_copies > 0 ? 'Request Borrow' : 'Unavailable'}
                      </button>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
          {!books.length && <div style={{ gridColumn:'1/-1', textAlign:'center', padding:60, color:'#9ca3af' }}>📚 No books found</div>}
        </div>
      )}

      {/* Pagination */}
      {Math.ceil(total/9) > 1 && (
        <div style={{ display:'flex', alignItems:'center', justifyContent:'center', gap:8, marginTop:24 }}>
          <button onClick={() => setPage(p => Math.max(1,p-1))} disabled={page===1} style={{ padding:'7px 16px', background:'#e8e0d0', border:'none', borderRadius:8, cursor:'pointer', opacity:page===1?0.4:1 }}>← Prev</button>
          <span style={{ fontSize:13, color:'#6b7280' }}>Page {page} of {Math.ceil(total/9)}</span>
          <button onClick={() => setPage(p => Math.min(Math.ceil(total/9),p+1))} disabled={page===Math.ceil(total/9)} style={{ padding:'7px 16px', background:'#e8e0d0', border:'none', borderRadius:8, cursor:'pointer', opacity:page===Math.ceil(total/9)?0.4:1 }}>Next →</button>
        </div>
      )}

      {/* Add/Edit Modal — only for staff */}
      {modal && isStaff && (
        <div style={{ position:'fixed', inset:0, background:'rgba(26,26,46,0.5)', backdropFilter:'blur(4px)', zIndex:1000, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
          <div style={{ background:'#fff', borderRadius:20, padding:28, width:'100%', maxWidth:560, maxHeight:'90vh', overflowY:'auto' }}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:22 }}>
              <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:20, fontWeight:700 }}>{modal==='add'?'Add New Book':'Edit Book'}</h2>
              <button onClick={() => setModal(null)} style={{ background:'#f5f0e8', border:'none', width:32, height:32, borderRadius:8, cursor:'pointer', fontSize:16 }}>✕</button>
            </div>
            {error && <div style={{ background:'#fee2e2', color:'#dc2626', padding:'10px 14px', borderRadius:9, fontSize:13, marginBottom:14 }}>{error}</div>}
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:14 }}>
              <div style={{ gridColumn:'1/-1' }}><label style={lbl}>Title *</label><input style={inp} value={form.title||''} onChange={e=>setForm(f=>({...f,title:e.target.value}))} /></div>
              <div><label style={lbl}>Author *</label><input style={inp} value={form.author||''} onChange={e=>setForm(f=>({...f,author:e.target.value}))} /></div>
              <div><label style={lbl}>ISBN</label><input style={inp} value={form.isbn||''} onChange={e=>setForm(f=>({...f,isbn:e.target.value}))} /></div>
              <div><label style={lbl}>Category</label>
                <select style={inp} value={form.category_id||''} onChange={e=>setForm(f=>({...f,category_id:Number(e.target.value)}))}>
                  <option value="">Select...</option>
                  {categories.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
              </div>
              <div><label style={lbl}>Publisher</label><input style={inp} value={form.publisher||''} onChange={e=>setForm(f=>({...f,publisher:e.target.value}))} /></div>
              <div><label style={lbl}>Year</label><input style={inp} type="number" value={form.published_year||''} onChange={e=>setForm(f=>({...f,published_year:Number(e.target.value)}))} /></div>
              <div><label style={lbl}>Total Copies</label><input style={inp} type="number" min={1} value={form.total_copies||1} onChange={e=>setForm(f=>({...f,total_copies:Number(e.target.value)}))} /></div>
              <div><label style={lbl}>Location</label><input style={inp} value={form.location||''} onChange={e=>setForm(f=>({...f,location:e.target.value}))} /></div>
              <div><label style={lbl}>Pages</label><input style={inp} type="number" value={form.pages||''} onChange={e=>setForm(f=>({...f,pages:Number(e.target.value)}))} /></div>
              <div><label style={lbl}>Language</label><input style={inp} value={form.language||'English'} onChange={e=>setForm(f=>({...f,language:e.target.value}))} /></div>
              <div style={{ gridColumn:'1/-1' }}><label style={lbl}>Description</label><textarea style={{...inp, minHeight:80, resize:'vertical'}} value={form.description||''} onChange={e=>setForm(f=>({...f,description:e.target.value}))} /></div>
            </div>
            <div style={{ display:'flex', gap:10, marginTop:20 }}>
              <button onClick={() => setModal(null)} style={{ flex:1, padding:'10px', background:'#f5f0e8', border:'none', borderRadius:10, cursor:'pointer', fontFamily:'inherit', fontSize:13 }}>Cancel</button>
              <button onClick={save} disabled={saving} style={{ flex:1, padding:'10px', background:'#1a1a2e', color:'#fff', border:'none', borderRadius:10, cursor:'pointer', fontFamily:'inherit', fontSize:13, fontWeight:600 }}>{saving?'Saving...':'Save Book'}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
